import { Flowise } from 'flowise';
import { Vex } from '@vex_dev/sdk';

const vex = new Vex({
  projectId: 'your-project-id',
  apiKey: process.env.VEX_API_KEY
});

const chatflow = await Flowise.loadChatflow('email-assistant-flow');

chatflow.setCallbackHandler({
  async onChainEnd(inputs: any, outputs: any) {
    if (outputs.intent) {
      await vex.verify({
        sessionId: inputs.sessionId,
        step: 'intent_detection',
        input: inputs.emailContent,
        output: outputs.intent,
        rules: ['intent_validity'],
        riskProfile: 'high'
      });
    }
  }
});

const result = await chatflow.chat({
  question: incomingEmail,
  sessionId: userSessionId
});

chatflow.on('draft_generated', async (draft: string, metadata: any) => {
  const verification = await vex.verify({
    sessionId: metadata.sessionId,
    step: 'pii_filtering',
    input: draft,
    context: {
      sender: metadata.sender,
      recipients: metadata.recipients
    },
    rules: ['no_pii', 'confidentiality'],
    overrides: {
      pii_threshold: 0.8
    }
  });

  if (!verification.pass) {
    throw new Error(`PII detected: ${verification.issues}`);
  }

  return draft;
});

// Custom node callback for vector store retrieval
const validateRecipients = async (retrievedDocs: any[], intent: string) => {
  const check = await vex.verify({
    sessionId: sessionId,
    step: 'recipient_validation',
    input: retrievedDocs.map(doc => doc.metadata.email),
    context: { intent },
    rules: ['domain_policy', 'relationship_validity'],
    metadata: {
      useCase: 'email_assistant',
      vectorStore: 'crm_contacts'
    }
  });

  return check.pass ? retrievedDocs : [];
};

const sendApproval = async (finalDraft: string, recipients: string[]) => {
  const toneCheck = await vex.verify({
    sessionId: sessionId,
    step: 'tone_approval',
    input: finalDraft,
    context: {
      recipients,
      senderRole: userRole,
      companyPolicy: 'professional'
    },
    rules: ['tone_appropriateness', 'content_accuracy'],
    riskProfile: 'critical'
  });

  if (toneCheck.pass) {
    await sendEmail(finalDraft, recipients);
  } else {
    await routeToHumanReview(toneCheck.issues);
  }
};

