// flowise.config.ts
import { VexCallbackHandler } from '@vex_dev/sdk/flowise';

const vexHandler = new VexCallbackHandler({
  projectId: process.env.VEX_PROJECT_ID!,
  apiKey: process.env.VEX_API_KEY!,
  rulesets: ['email-pii', 'tone-control', 'recipient-safety'],
  riskProfile: 'high',
  sessionKey: 'email_thread_id'
});

export default {
  chatflows: {
    'email-assistant': {
      callbacks: [vexHandler],
      overrideConfig: {
        temperature: 0.3,
        maxTokens: 2000
      }
    }
  }
};

import { ToolNode } from 'flowise';
import { Vex } from '@vex_dev/sdk';

class SafeAttachmentTool extends ToolNode {
  constructor() {
    super();
    this.name = 'safe_attachment_processor';
  }

  async execute(input: any) {
    try {
      const vex = new Vex({ /* config */ });
      const result = await vex.verify({
        step: 'attachment_processing',
        input: input.file,
        rules: ['file_type_safe', 'extraction_success']
      });

      if (!result.pass) {
        throw new Error('Attachment verification failed');
      }

      return await this.processAttachment(input.file);
    } catch (error) {
      await vex.captureError(error, { context: input });
      throw error;
    }
  }
}

// Agent handoff middleware
const contextGuard = async (fromAgent: string, toAgent: string, state: any) => {
  const continuityCheck = await vex.verify({
    sessionId: state.sessionId,
    step: `handoff_${fromAgent}_to_${toAgent}`,
    input: state,
    rules: ['context_preservation'],
    metadata: {
      emailThreadId: state.threadId,
      requiredKeys: ['intent', 'recipients', 'attachments']
    }
  });

  if (!continuityCheck.pass) {
    throw new Error('Context lost during agent handoff');
  }

  return state;
};
